"""
matplotlib compatibility layer for OfflinAi.
Routes all plotting through plotly for high-quality interactive charts.
Supports the common matplotlib.pyplot API surface.
"""

__version__ = "3.9.0-offlinai"
__file__ = __file__

_backend = "offlinai_plotly"

def use(backend, **kwargs):
    """Accepted but ignored — always uses plotly backend."""
    global _backend
    _backend = backend

def get_backend():
    return _backend

def set_loglevel(level):
    pass

def rc_context(rc=None, fname=None):
    """No-op context manager."""
    import contextlib
    return contextlib.nullcontext()

# rcParams as a dict-like object
class _RcParams(dict):
    def __init__(self):
        super().__init__({
            'figure.figsize': [6.4, 4.8],
            'figure.dpi': 100,
            'savefig.dpi': 150,
            'font.size': 10,
            'font.family': ['sans-serif'],
            'axes.labelsize': 'medium',
            'axes.titlesize': 'large',
            'axes.grid': False,
            'lines.linewidth': 1.5,
            'lines.markersize': 6,
            'legend.fontsize': 'medium',
            'image.cmap': 'viridis',
            'text.usetex': False,
        })

    def __missing__(self, key):
        return None

rcParams = _RcParams()
rcParamsDefault = _RcParams()

def rc(group, **kwargs):
    """Update rcParams."""
    for k, v in kwargs.items():
        rcParams[f'{group}.{k}'] = v

def rcdefaults():
    global rcParams
    rcParams = _RcParams()

